<template>
  <!-- 左侧分类导航 -->
  <div class="header">
    <!-- 用户信息 -->
    <el-row type="flex" style="padding-top: 1px">
      <el-col :span="16" style="text-align: left; margin-left: 5px; white-space: nowrap"
        ><span v-if="headerConfig && headerConfig.account">{{ userInfo.account }}</span
        ><span v-if="headerConfig && headerConfig.member">
          <a style="cursor: pointer; color: cyan; text-decoration: underline" @click="handleMemberClick">{{ memberVipLevel }}</a></span
        >
        <span v-if="headerConfig && headerConfig.coin">
          Rug币:
          <a style="cursor: pointer; color: cyan; text-decoration: underline" @click="handleRecharge">{{ userInfo.coin || 0 }}</a></span
        >
        <span v-if="headerConfig && headerConfig.version && currentVersion" @click="openBrowser(versionHistoryUrl)"
          >Beta <span style="cursor: pointer; font-size: 14px">v{{ currentVersion }}</span></span
        >
      </el-col>
      <el-col :span="8" style="text-align: right; margin-right: 5px; white-space: nowrap">
        <span v-if="headerConfig && headerConfig.tutorial" style="cursor: pointer" @click="openBrowser(tutorialUrl)">教程</span>
        <span v-if="headerConfig && headerConfig.recharge" style="cursor: pointer" @click="handleRecharge">充值</span>
        <span v-if="headerConfig && headerConfig.setting" style="cursor: pointer" @click="handleSetting">设置</span>
        <span style="cursor: pointer" @click="userExit">退出</span></el-col
      >
    </el-row>

    <PurchaseMember ref="purchaseMemberRef" :userInfo="userInfo" :vipPackageList="vipPackageList" @refreshUserInfo="onRefreshUserInfo" />
  </div>
</template>

<script>
import { getMemUserInfo, getLatestVersion, getMultiConfig } from '@/api/main';
import { removeToken } from '@/utils/auth';
import { getPluginVersion } from '@/utils/cepspy';
import { openExternalLink } from '@/utils/cepInterface';
import PurchaseMember from '@/components/PurchaseMember.vue';

export default {
  name: 'Header',
  components: { PurchaseMember },
  data() {
    return {
      headerConfig: {},
      userInfo: {},
      vipPackageList: [],
      currentVersion: null,
      versionHistoryUrl: null,
      tutorialUrl: null
    };
  },
  computed: {
    memberVipLevel() {
      if (this.userInfo && this.userInfo.level) {
        const item = this.vipPackageList.find((item) => item.id === String(this.userInfo.level));
        return item ? item.name : '萌新';
      }
      return '萌新';
    }
  },
  created() {
    this.getUserInfo();
    this.getConfig();
  },
  methods: {
    handleRecharge() {
      this.$emit('handleRecharge', this.handleRecharge);
    },
    handleMemberClick() {
      this.$refs.purchaseMemberRef.handleOpen();
    },
    onRefreshUserInfo() {
      this.getUserInfo();
      this.$emit('refreshUserInfo');
    },
    handleSetting() {
      this.$emit('handleSetting', this.handleSetting); // 通知父组件刷新用户信息
    },
    userExit() {
      removeToken();
      this.$router.push({ name: 'Login' });
    },
    openBrowser(url) {
      // 打开外部链接
      if (url) {
        openExternalLink(url);
      }
    },
    getUserInfo() {
      // 获取用户信息
      getMemUserInfo().then((response) => {
        this.userInfo = response.data;
      });
    },
    getConfig() {
      let params = {
        codeList: ['sys.vipConfig', 'sys.main.header', 'sys.versionHistoryUrl', 'sys.tutorialUrl']
      };
      // 获取配置信息
      Promise.all([getLatestVersion(), getMultiConfig(params)]).then(([versionInfo, multiConfig]) => {
        this.headerConfig = JSON.parse(multiConfig.data['sys.main.header']) || {};
        this.lasterVersion = versionInfo.data;
        this.currentVersion = getPluginVersion();
        this.versionHistoryUrl = multiConfig.data['sys.versionHistoryUrl'];
        this.vipPackageList = JSON.parse(multiConfig.data['sys.vipConfig']) || [];
        this.tutorialUrl = multiConfig.data['sys.tutorialUrl'] || '';
      });
    }
  }
};
</script>

<style scoped>
.header {
  display: flex;
  flex-direction: column;
  height: 4vh;
  background-color: black;
  font-size: 16px;
}
</style>
